// Accept either a body with {id} or a top-level {id} from Execute Workflow each mode.
const data = $input.item.json || {};
const appt_id = (data.body && data.body.id) || data.id || null;
if (!appt_id) return { json: { _error: true, error: 'appointment id required', ok: false } };
return { json: { appointment_id: appt_id } };

// Preflight: must have lead.phone and client.calendly_link. If either
// missing, short-circuit to a structured skip (logged but not failed).
const arr = $input.item.json || [];
const row = Array.isArray(arr) && arr.length > 0 ? arr[0] : null;
if (!row) return { json: { _skip: true, skip_reason: 'appointment not found', ok: false } };

const lead = row.leads || {};
const client = row.clients || {};
const phone = (lead.phone || '').replace(/[^0-9]/g, '');
const rebook = client.calendly_link || '';

if (!phone) return { json: { _skip: true, skip_reason: 'lead.phone missing', ok: false, lead_id: lead.id, appointment_id: row.id } };
if (!rebook) return { json: { _skip: true, skip_reason: 'client.calendly_link missing', ok: false, lead_id: lead.id, appointment_id: row.id } };

const name = (lead.first_name || 'there').trim();
const clientName = (client.client_name || 'our team').trim();
// Default template — can be overridden per-agent from agent_calendar_prefs.no_show_sms_template at a later phase.
const message = 'Hi ' + name + ' — ' + clientName + ' here. Sorry we missed you on our call today. No worries — pick a better time here: ' + rebook + ' Reply STOP to opt out.';

// TESTING MODE redirect: in dev, route all recovery SMS to Mary's test phone.
// Leave the const below as-is during dev; delete to go live.
const TESTING_PHONE = '+15555550123'; // TESTING MODE — replace with Mary's real phone or remove before production
const send_to = TESTING_PHONE; // TESTING MODE — remove this override before production

return { json: {
  appointment_id: row.id,
  lead_id: lead.id,
  client_id: client.id,
  message_text: message,
  send_to_phone: send_to,
  rebook_link: rebook
} };

// Parse Twilio response
const resp = $input.item.json || {};
const ctx = $('Compose SMS').first().json;
const status = resp.status || null;
const ok = !!(resp.sid && !resp.error_code && ['queued','sent','delivered','accepted'].includes(String(status).toLowerCase()));
const err = ok ? null : (resp.error_message || resp.message || JSON.stringify(resp).slice(0, 500));
return { json: Object.assign({}, ctx, { twilio_ok: ok, twilio_sid: resp.sid || null, twilio_status: status, twilio_error: err }) };

// Pass-through so webhook responseData resolves cleanly.
const src = $input.item.json || {};
return { json: {
  ok: !!src.twilio_ok,
  appointment_id: src.appointment_id || null,
  lead_id: src.lead_id || null,
  twilio_sid: src.twilio_sid || null,
  error: src.twilio_error || null
} };
